    27	    /// Render the status bar for a given width.
    28	    pub fn render(self: *const StatusBar, alloc: std.mem.Allocator, cols: u32, ctx: *const format.FormatContext) ![]u8 {
    29	        if (!self.enabled or cols == 0) {
    30	            return try alloc.alloc(u8, 0);
    31	        }
    32	
    33	        const left = try format.expand(alloc, self.left, ctx);
    34	        defer alloc.free(left);
    35	        const right = try format.expand(alloc, self.right, ctx);
    36	        defer alloc.free(right);
