    41	    /// Render the status bar with explicit left/window-list/right sections.
    42	    pub fn renderSections(
    43	        self: *const StatusBar,
    44	        alloc: std.mem.Allocator,
    45	        cols: u32,
    46	        left: []const u8,
    47	        center: []const u8,
    48	        right: []const u8,
    49	    ) ![]u8 {
    50	        if (!self.enabled or cols == 0) {
    51	            return try alloc.alloc(u8, 0);
    52	        }
    53	
    54	        var leading: std.ArrayListAligned(u8, null) = .empty;
    55	        defer leading.deinit(alloc);
    56	
    57	        if (left.len > 0) {
    58	            try leading.appendSlice(alloc, left);
    59	        }
    60	        if (center.len > 0) {
    61	            if (leading.items.len > 0) {
    62	                try leading.append(alloc, ' ');
    63	            }
    64	            try leading.appendSlice(alloc, center);
    65	        }
    66	
    67	        var line: std.ArrayListAligned(u8, null) = .empty;
    68	        errdefer line.deinit(alloc);
    69	
    70	        const right_len = @min(right.len, cols);
    71	        const leading_budget = cols - right_len;
    72	        const leading_len = @min(leading.items.len, leading_budget);
    73	        try line.appendSlice(alloc, leading.items[0..leading_len]);
    74	
    75	        while (line.items.len < leading_budget) {
    76	            try line.append(alloc, ' ');
    77	        }
    78	
    79	        try line.appendSlice(alloc, right[0..right_len]);
    80	
    81	        return try line.toOwnedSlice(alloc);
    82	    }
