    84	    pub fn writeSections(
    85	        self: *const StatusBar,
    86	        out: *output_mod.Output,
    87	        cols: u32,
    88	        left: []const u8,
    89	        center: []const u8,
    90	        right: []const u8,
    91	    ) void {
    92	        if (!self.enabled or cols == 0) return;
    93	
    94	        const total_cols: usize = cols;
    95	        const left_visible = style_mod.visibleLenInline(left);
    96	        const center_visible = style_mod.visibleLenInline(center);
    97	        const right_visible = @min(style_mod.visibleLenInline(right), total_cols);
    98	        const spacer_visible: usize = if (left_visible > 0 and center_visible > 0) 1 else 0;
    99	        const leading_budget = total_cols - right_visible;
   100	
   101	        applyOutputStyle(out, self.style);
   102	
   103	        var leading_written = writeStyledText(out, self.style, left, leading_budget);
   104	        if (leading_written < leading_budget and spacer_visible > 0) {
   105	            applyOutputStyle(out, self.style);
   106	            out.writeBytes(" ");
   107	            leading_written += 1;
   108	        }
   109	        if (leading_written < leading_budget) {
   110	            leading_written += writeStyledText(out, self.style, center, leading_budget - leading_written);
   111	        }
   112	
   113	        if (leading_written < leading_budget) {
   114	            applyOutputStyle(out, self.style);
   115	            var remaining = leading_budget - leading_written;
   116	            while (remaining > 0) : (remaining -= 1) {
   117	                out.writeBytes(" ");
   118	            }
   119	        }
   120	
   121	        _ = writeStyledText(out, self.style, right, right_visible);
   122	    }
   123	};
