   125	fn applyOutputStyle(out: *output_mod.Output, style: style_mod.Style) void {
   126	    out.attrReset();
   127	    out.setAttrs(style.attrs);
   128	    out.setFg(style.fg);
   129	    out.setBg(style.bg);
   130	}
