   132	fn writeStyledText(out: *output_mod.Output, base_style: style_mod.Style, raw: []const u8, visible_limit: usize) usize {
   133	    var written: usize = 0;
   134	    var i: usize = 0;
   135	    var current_style = base_style;
   136	
   137	    while (i < raw.len and written < visible_limit) {
   138	        if (style_mod.inlineStyleEnd(raw, i)) |end| {
   139	            current_style = style_mod.applyDirective(base_style, current_style, raw[i + 2 .. end]);
   140	            applyOutputStyle(out, current_style);
   141	            i = end + 1;
   142	            continue;
   143	        }
   144	
   145	        const next_style = std.mem.indexOfPos(u8, raw, i, "#[") orelse raw.len;
   146	        const chunk = raw[i..next_style];
   147	        if (chunk.len == 0) {
   148	            i = next_style;
   149	            continue;
   150	        }
   151	
   152	        const chunk_visible = @min(chunk.len, visible_limit - written);
   153	        out.writeBytes(chunk[0..chunk_visible]);
   154	        written += chunk_visible;
   155	        i += chunk_visible;
   156	
   157	        if (chunk_visible < chunk.len) break;
   158	    }
   159	
   160	    return written;
   161	}
